import{_ as o,o as c,c as d,a2 as t}from"./chunks/framework.BKG_UbFK.js";const h=JSON.parse('{"title":"आर्किटेक्चर","description":"","frontmatter":{},"headers":[],"relativePath":"hi/guide/architecture.md","filePath":"hi/guide/architecture.md"}'),r={name:"hi/guide/architecture.md"};function a(i,e,l,s,n,_){return c(),d("div",null,[...e[0]||(e[0]=[t('<h1 id="आर्किटेक्चर" tabindex="-1">आर्किटेक्चर <a class="header-anchor" href="#आर्किटेक्चर" aria-label="Permalink to &quot;आर्किटेक्चर&quot;">​</a></h1><h2 id="resolution-कैसे-काम-करता-है" tabindex="-1">Resolution कैसे काम करता है <a class="header-anchor" href="#resolution-कैसे-काम-करता-है" aria-label="Permalink to &quot;Resolution कैसे काम करता है&quot;">​</a></h2><p><code>resolveFor()</code>, Clearance के प्रासंगिक प्राधिकरण का मूल है - पूरे API के लिए देखें <a href="/clearance-docs/hi/features/contextual-authorization.html">प्रासंगिक प्राधिकरण</a>। यह तीन स्रोतों को इस प्राथमिकता क्रम में मिलाता है:</p><ol><li><strong>प्रासंगिक भूमिका अनुदान</strong> - उन भूमिकाओं से अनुमतियाँ जो उपयोगकर्ता विशेष रूप से इस संदर्भ के भीतर रखता है (<code>clr_role_ctx</code>)।</li><li><strong>वैश्विक भूमिका अनुदान</strong> - उपयोगकर्ता की globally-असाइन की गई Spatie भूमिकाओं से अनुमतियाँ (ताकि <code>super_admin</code> और अन्य वैश्विक भूमिकाएं किसी भी संदर्भ के लिए <code>canIn()</code> को संतुष्ट करें)।</li><li><strong>प्रति-संदर्भ ओवरराइड</strong> (<code>clr_ctx_overrides</code>) - <code>forced_on</code> उपरोक्त के ऊपर एक अनुमति जोड़ता है; <code>forced_off</code> इसे हटा देता है, भले ही वह अनुमति किसी वैश्विक भूमिका द्वारा दी गई हो। एक deny हमेशा जीतती है।</li></ol><div class="warning custom-block"><p class="custom-block-title">एक deny हमेशा जीतता है</p><p><code>forced_off</code>, किसी वैश्विक भूमिका या प्रासंगिक भूमिका अनुदान द्वारा दी गई किसी भी अनुमति को override कर देता है। उसी user/permission/context के लिए <code>forced_off</code> ओवरराइड को हटाए बिना उसे &quot;out-rank&quot; करने का कोई तरीका नहीं है।</p></div><h2 id="डेटाबेस" tabindex="-1">डेटाबेस <a class="header-anchor" href="#डेटाबेस" aria-label="Permalink to &quot;डेटाबेस&quot;">​</a></h2><p>Clearance 6 टेबल्स का स्वामी है और कभी भी Spatie की मूल टेबल्स (<code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code>, <code>role_has_permissions</code>) में बदलाव नहीं करता। <code>roles.id</code>/<code>permissions.id</code> को संदर्भित करने वाले सभी FK, जब तक अन्यथा न बताया जाए, delete पर cascade करते हैं; Spatie टेबल्स में <code>clr_*</code> की ओर इशारा करने वाला कोई FK नहीं है।</p><table tabindex="0"><thead><tr><th>टेबल</th><th>मुख्य कॉलम</th></tr></thead><tbody><tr><td><code>clr_meta</code></td><td><code>subject_type</code>, <code>subject_key</code> (एक साथ unique) - <code>display_name</code>, <code>description</code>, <code>icon_svg</code>, <code>color</code> - किसी भूमिका या गार्ड के लिए डिस्प्ले मेटाडेटा</td></tr><tr><td><code>clr_role_meta</code></td><td><code>role_id</code> (unique, FK -&gt; <code>roles</code>) - <code>is_locked</code>, <code>scope</code> (<code>global</code>|<code>contextual</code>), <code>context_types</code> (json) - <code>parent_role_id</code> (nullable FK -&gt; <code>roles</code>, <code>ON DELETE SET NULL</code>) - सीलिंग भूमिका</td></tr><tr><td><code>clr_guards</code></td><td><code>name</code> (unique), <code>driver</code>, <code>provider</code> - पैनल के माध्यम से प्रबंधित गार्ड</td></tr><tr><td><code>clr_settings</code></td><td><code>key</code> (unique), <code>value</code> - runtime key/value स्टोर (डिफ़ॉल्ट भूमिका, आदि)</td></tr><tr><td><code>clr_role_ctx</code></td><td><code>user_id</code>, <code>role_id</code> (FK -&gt; <code>roles</code>), <code>context_type</code>, <code>context_id</code> - प्रासंगिक भूमिका असाइनमेंट, <code>(user, role, context_type, context_id)</code> के अनुसार unique</td></tr><tr><td><code>clr_ctx_overrides</code></td><td><code>user_id</code>, <code>role_id</code> (FK -&gt; <code>roles</code>), <code>permission_id</code> (FK -&gt; <code>permissions</code>), <code>context_type</code>, <code>context_id</code>, <code>type</code> (<code>forced_on</code>|<code>forced_off</code>) - प्रति-उपयोगकर्ता, प्रति-संदर्भ अनुमति ओवरराइड</td></tr></tbody></table><h2 id="spatie-की-टेबल्स-को-कभी-नहीं-छूता" tabindex="-1">Spatie की टेबल्स को कभी नहीं छूता <a class="header-anchor" href="#spatie-की-टेबल्स-को-कभी-नहीं-छूता" aria-label="Permalink to &quot;Spatie की टेबल्स को कभी नहीं छूता&quot;">​</a></h2><p>Clearance को <code>spatie/laravel-permission</code> को प्रतिस्थापित करने के बजाय उसके साथ रहने के लिए डिज़ाइन किया गया है। हर <code>Role</code> और <code>Permission</code> रिकॉर्ड जो एक Clearance पैनल बनाता या संपादित करता है, वह एक असली Spatie मॉडल है, जो Spatie की अपनी टेबल्स में संग्रहीत है। Clearance कभी भी ऐसा migration नहीं चलाता जो <code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code>, या <code>role_has_permissions</code> में से किसी में कॉलम जोड़े, या इनमें से किसी से FK लिखे।</p><p>Clearance का अपना सारा डेटा - डिस्प्ले मेटाडेटा, भूमिका दायरा और सीलिंग, प्रासंगिक असाइनमेंट, प्रति-संदर्भ ओवरराइड, गार्ड परिभाषाएं, और सेटिंग्स - विशेष रूप से ऊपर दी गई 6 <code>clr_*</code> टेबल्स में रहता है। इसका मतलब है:</p><ul><li>Clearance को uninstall करना आपके मौजूदा Spatie भूमिका/अनुमति डेटा को कभी corrupt होने का जोखिम नहीं देता।</li><li>कोई भी कोड जो पहले से Spatie के मॉडल या टेबल्स को सीधे पढ़ता है, बिना किसी बदलाव के काम करता रहता है।</li><li>Clearance की प्रासंगिक और सीलिंग सुविधाएं विशुद्ध रूप से additive परतें हैं जो query के समय resolve होती हैं (<code>resolveFor()</code> और <code>RoleService</code> के माध्यम से), Spatie के schema में built-in नहीं हैं।</li></ul><h2 id="संबंधित" tabindex="-1">संबंधित <a class="header-anchor" href="#संबंधित" aria-label="Permalink to &quot;संबंधित&quot;">​</a></h2><ul><li><a href="/clearance-docs/hi/features/contextual-authorization.html">प्रासंगिक प्राधिकरण</a> - <code>canIn()</code>, <code>hasRoleIn()</code>, Blade directives, <code>ContextService</code></li><li><a href="/clearance-docs/hi/features/roles.html">भूमिकाएं</a> - दायरा और सीलिंग भूमिकाएं, <code>RoleService::setParent()</code></li><li><a href="/clearance-docs/hi/guide/migration.html">माइग्रेशन</a> - किसी मौजूदा Spatie install पर <code>clr_meta</code>/<code>clr_role_meta</code>/<code>clr_guards</code> को backfill करना</li><li><a href="/clearance-docs/hi/guide/security.html">सुरक्षा</a> - सीलिंग और ओवरराइड मॉडल privilege escalation को कैसे रोकता है</li></ul>',14)])])}const p=o(r,[["render",a]]);export{h as __pageData,p as default};
